I agree. Do you want something like the below? It seems to work in every case, but for a detail: when an input pipe exists, the two arguments become optional.
```
import os
import sys
from stat import S_ISFIFO
import click

INPUT_PIPED = S_ISFIFO(os.fstat(0).st_mode)
OUTPUT_PIPED = sys.stdout.isatty()


@click.command(context_settings=dict(help_option_names=['-h', '--help']))
@click.argument('notebook_path', required=not INPUT_PIPED)
@click.argument('output_path', required=not (INPUT_PIPED or OUTPUT_PIPED))
def papermill(notebook_path, output_path):
    if INPUT_PIPED and notebook_path and not output_path:
        output_path = notebook_path
        notebook_path = '-'
    else:
        notebook_path = notebook_path or '-'
        output_path = output_path or '-'

    print('notebook_path={}'.format(notebook_path))
    print('output_path={}'.format(output_path))


if __name__ == '__main__':
    papermill()
